import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface RecentContact {
  name: string;
  lastMessage: string;
  time: string;
}

interface MessageVolume {
  hour: string;
  messages: number;
}

interface WidgetData {
  unreadConversations: number;
  recentContacts: RecentContact[];
  messageVolume: MessageVolume[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

interface ResponseData {
  data: WidgetData;
  meta: MetaData;
}

export default function Widget() {
  const { data, meta } = response as ResponseData;
  const { unreadConversations, recentContacts, messageVolume } = data;
  const { primaryColor, accentColor } = meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={700} color={primaryColor}>
              Messenger Hub
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Unread Conversations: {unreadConversations}
            </Typography>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {recentContacts.map((contact, index) => (
              <Chip
                key={index}
                label={`${contact.name}: ${contact.lastMessage}`}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: accentColor, color: '#FFFFFF' }}
              />
            ))}
          </Stack>

          <BarChart
            height={140}
            series={[
              {
                data: messageVolume.map(m => m.messages),
                color: primaryColor,
              },
            ]}
            xAxis={[
              {
                data: messageVolume.map(m => m.hour),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#6B7280',
                },
              }
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
